import Message from "./Message";
import Composer from "./Composer";

export default function ChatArea({ chat, onSend, onStream }) {
    if (!chat) return null;

    const isEmpty = chat.messages.length === 0;

    return (
        <section className="chat-area">
            {isEmpty ? (
                <div className="empty">
                    <h1>What can I help with?</h1>
                    <Composer
                        center
                        onSend={(text) => {
                            onSend(text);
                            onStream(text);
                        }}
                    />
                </div>
            ) : (
                <>
                    <div className="messages">
                        {chat.messages.map((msg, i) => (
                            <Message key={i} {...msg} />
                        ))}
                    </div>
                    <Composer
                        onSend={(text) => {
                            onSend(text);
                            onStream(text);
                        }}
                    />
                </>
            )}
        </section>
    );
}
